      href={props.href}
      aria-current={isCurrent ? "page" : undefined}
      onClick={(event) => {
        event.preventDefault();
        navigateToRoute(props.href);
        window.dispatchEvent(new PopStateEvent("popstate"));
      }}
    >
      {props.children}
