      const channel = clampByte(value * 255);
      imageData.data[pixelIndex] = channel;
      imageData.data[pixelIndex + 1] = channel;
      imageData.data[pixelIndex + 2] = channel;
      imageData.data[pixelIndex + 3] = 255;
